code.Java:
import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    static final int MAX = 1000001;
    static int[] lp = new int[MAX];
    public static void sieve() {
        for (int i = 2; i < MAX; i++) {
            if (lp[i] == 0) {
                lp[i] = i;
                for (int j = i * i; j < MAX; j += i) {
                    if (lp[j] == 0) lp[j] = i;
                }
            }
        }
    }
    public static int strength(int N) {
        int value = 0, temp = N;
        while (temp != 1) {
            value += N / lp[temp];
            temp /= lp[temp];
        }
        return value;
    }
    public static void main(String[] args) {
        sieve();
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int k = sc.nextInt();
            long sum = 0;
            for (int i = N; i <= N * k; i += N) {
                sum += strength(i);
                sum %= MOD;
            }
            System.out.println(sum);
        }
    }
