code.JavaScript:
const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;
const MAX = 1000001;
const lp = new Array(MAX).fill(0);
function sieve() {
    for (let i = 2; i < MAX; i++) {
        if (lp[i] === 0) {
            lp[i] = i;
            for (let j = i * i; j < MAX; j += i) {
                if (lp[j] === 0) lp[j] = i;
            }
        }
    }
}
function strength(N) {
    let value = 0, temp = N;
    while (temp !== 1) {
        value += Math.floor(N / lp[temp]);
        temp = Math.floor(temp / lp[temp]);
    }
    return value;
}
sieve();
const T = parseInt(input[idx++]);
for (let i = 0; i < T; i++) {
    const [N, k] = input[idx++].split(' ').map(Number);
    let sum = 0;
    for (let j = N; j <= N * k; j += N) {
        sum += strength(j);
        sum %= MOD;
    }
    console.log(sum);
}
